class Playground {
    async run(inputs) {
        const ops = inputs[0].split(',');
        const vals = inputs[1].split(',');

        await this.q1.init([]);
        await this.q2.init([]);
        await this.stack_view.init([]);

        const results = [];

        for (let i = 0; i < ops.length; i++) {
            const op = ops[i].trim();
            const val = vals[i] && vals[i].trim() !== 'null' ? vals[i].trim() : null;

            if (op === 'push') {
                this.log(`Pushing ${val} to stack. Step 1: Enqueue to Queue 2.`);
                this.q2.enqueue(val);
                await this.await();

                this.log(`Step 2: Move all elements from Queue 1 to Queue 2 to maintain LIFO order.`);
                while (!this.q1.isEmpty()) {
                    const moved = this.q1.dequeue();
                    this.q2.enqueue(moved);
                    await this.await();
                }

                this.log(`Step 3: Move everything back to Queue 1 so it remains the primary storage.`);
                while (!this.q2.isEmpty()) {
                    const moved = this.q2.dequeue();
                    this.q1.enqueue(moved);
                    await this.await();
                }

                this.stack_view.push(val);
                this.log(`Successfully pushed ${val}. Queue 1 front now represents the stack top.`);
                await this.await();
                results.push(null);
            } 
            else if (op === 'pop') {
                if (this.q1.isEmpty()) {
                    this.log("Stack is empty, cannot pop.");
                    results.push(null);
                } else {
                    const popped = this.q1.dequeue();
                    this.stack_view.pop();
                    this.log(`Popped ${popped} from the front of Queue 1.`);
                    await this.await();
                    results.push(popped);
                }
            } 
            else if (op === 'top') {
                if (this.q1.isEmpty()) {
                    this.log("Stack is empty, no top element.");
                    results.push(null);
                } else {
                    const topVal = this.q1.peek();
                    this.log(`Top element is ${topVal} (front of Queue 1).`);
                    this.q1.highlight(0, "#00e0ff");
                    await this.await();
                    results.push(topVal);
                }
            } 
            else if (op === 'empty') {
                const isEmpty = this.q1.isEmpty();
                this.log(`Checking if Queue 1 is empty: ${isEmpty}`);
                await this.await();
                results.push(isEmpty);
            }
        }

        return results;
    }
}
